import{_ as a,c as e,o as i,ag as t}from"./chunks/framework.S-Qvb3wi.js";const p=JSON.parse('{"title":"DGrid 제네시스 멤버십 프로그램 개요","description":"","frontmatter":{},"headers":[],"relativePath":"kr/Program-Overview.md","filePath":"kr/Program-Overview.md"}'),o={name:"kr/Program-Overview.md"};function d(l,r,s,n,_,c){return i(),e("div",null,r[0]||(r[0]=[t('<h1 id="dgrid-제네시스-멤버십-프로그램-개요" tabindex="-1">DGrid 제네시스 멤버십 프로그램 개요 <a class="header-anchor" href="#dgrid-제네시스-멤버십-프로그램-개요" aria-label="Permalink to &quot;DGrid 제네시스 멤버십 프로그램 개요&quot;">​</a></h1><h2 id="dgrid-제네시스-멤버십이란-무엇인가" tabindex="-1">DGrid 제네시스 멤버십이란 무엇인가? <a class="header-anchor" href="#dgrid-제네시스-멤버십이란-무엇인가" aria-label="Permalink to &quot;DGrid 제네시스 멤버십이란 무엇인가?&quot;">​</a></h2><p>DGrid 제네시스 멤버십은 DGrid 탈중앙화 AI 생태계의 핵심 증빙서류이며, 초기 참여자가 네트워크와 깊게 결합되는 상징적인 신분이다. 사용자가 제네시스 멤버십 서비스를 구독하면 전용 신분 증빙서류로 <strong>Genesis Pass NFT</strong>를 받게 된다. 일반 멤버십 혜택과 달리 이 NFT를 보유한 제네시스 멤버는 높은 가치의 AI 자원 사용 권한을 직접 얻을 수 있을 뿐만 아니라, 네트워크 발전 의사결정에 깊이 참여하고 생태계 성장 혜택을 공유할 수 있다.</p><p>네트워크의 장기적인 안정 운영과 생태계 확장을 위해 제네시스 멤버는 멤버 자격을 유지하고 생태계 구축에 적극적으로 참여하기만 하면 안정적인 경제적 보상을 받을 수 있다. 생태계를 장기적으로 지원하는 홀더에게는 향후 추가적인 생태계 보상을 받을 기회도 제공된다. 이번 제네시스 멤버십 프로그램은 특별히 저문턱·평등화된 참여 메커니즘을 구축하여, 다양한 배경을 가진 커뮤니티 회원 모두가 탈중앙화 AI 발전의 초기 기회를 잡을 수 있도록 했다.</p><h2 id="제네시스-멤버십에-가입해야-하는-이유는-무엇인가" tabindex="-1">제네시스 멤버십에 가입해야 하는 이유는 무엇인가? <a class="header-anchor" href="#제네시스-멤버십에-가입해야-하는-이유는-무엇인가" aria-label="Permalink to &quot;제네시스 멤버십에 가입해야 하는 이유는 무엇인가?&quot;">​</a></h2><p>탈중앙화 AI 경제가 부상하는 핵심 단계에서 DGrid 제네시스 멤버가 되는 것은 &#39;관찰자&#39;에서 &#39;공동 건설자&#39;로 변모하는 것을 의미한다. 생태계에 다양한 가치를 제공하는 동시에 개인과 네트워크의 상생을 실현할 수 있다:</p><ul><li>탈중앙화 기반을 공고히 하다: 네트워크의 탈중앙화 구조를 유지하도록 지원하고 외부 위험에 대한 저항력을 높여 생태계의 장기 안정을 보장한다.</li><li>생태계 규모 확장을 추진하다: 모델 배포·인프라 운영 등 업무에 참여하여 탈중앙화 AI 추론 네트워크의 영역 확장을 지원한다.</li><li>고품질 AI 서비스를 보급하다: 실질적인 참여를 통해 네트워크 운영을 지원하여, 더 많은 사용자와 개발자가 저비용으로 고품질 AI 자원을 활용할 수 있도록 한다.</li><li>풍부한 보상을 획득하다: 생태계에 기여한 만큼 <strong>$DGAI 토큰</strong> 및 기타 전용 보상을 받고 네트워크 성장 혜택을 공유한다.</li></ul>',7)]))}const m=a(o,[["render",d]]);export{p as __pageData,m as default};
